document.addEventListener('DOMContentLoaded', () => {
  const footer = document.querySelector('.premium-footer');
  const layerBack = document.querySelector('.layer-back');
  const layerMid = document.querySelector('.layer-mid');
  const layerFront = document.querySelector('.layer-front');
  const sunMoon = document.querySelector('.celestial-body');

  let ticking = false;

  const updateParallax = () => {
    const footerRect = footer.getBoundingClientRect();
    const windowHeight = window.innerHeight;

    if (footerRect.top < windowHeight && footerRect.bottom > 0) {
      const scrollProgress = windowHeight - footerRect.top;
    
      if (layerBack) layerBack.style.transform = `translateY(${scrollProgress * 0.15}px)`;
      if (layerMid) layerMid.style.transform = `translateY(${scrollProgress * 0.08}px)`;
      if (layerFront) layerFront.style.transform = `translateY(${scrollProgress * 0.02}px)`;
      if (sunMoon) sunMoon.style.transform = `translateY(${scrollProgress * 0.25}px)`;
    }
    
    ticking = false;
  };

  window.addEventListener('scroll', () => {
    if (!ticking) {
      window.requestAnimationFrame(updateParallax);
      ticking = true;
    }
  }, { passive: true }); 
});


